Script.script:
status_bar = status_bar or {}

status_bar.configs = status_bar.configs or 
  {
    fontsize = 10,
    visible = true
  }

status_bar.char = status_bar.char or
  {
    mood = nil,
    posture = nil,
    hps = {
      max = nil,
      current = nil,
      est_max = nil,
      est_min = nil
    },
    sps = {
      max = nil,
      current = nil,
      est_max = nil,
      est_min = nil
    },
    dps = {
      max = nil,
      current = nil,
      est_max = nil,
      est_min = nil
    },
    mvs = {
      max = nil,
      current = nil,
      est_max = nil,
      est_min = nil
    },
    autoflee = nil,
    fleelag = {
      min = nil,
      max = nil
    },
    charge_pulses = {
      min = nil,
      max = nil
    },
    notice = nil,
    sneak = nil,
    one_power = nil,
    armor = nil,
    int = nil,
    wil = nil,
    con = nil,
  }

function status_bar:build()
  if self.container then      
    self.container:save()
    self.container:delete()
    self.container = nil
  end

  self.container = Adjustable.Container:new({
    name = "status_bar.container",
    adjLabelstyle = [[
      background-color: rgba(220,220,220,100%);
      border: 5px groove grey;
    ]],
    buttonstyle=[[
      QLabel{
        border-radius: 7px;
        background-color: rgba(140,140,140,100%);
      }
      QLabel::hover{
        background-color: rgba(160,160,160,50%);
      }
    ]],
    x = "0%", y = "-3%",
    width = "50%", height = "3%",
    buttonFontSize = 10,
    buttonsize = 20,
    titleText = "Status Bar",
    titleTxtColor = "black",
    padding = 15,
    autoSave = true,
    autoLoad = true,
  })

  for _, tab in pairs(self.tabs) do
    self[tab] = Geyser.Label:new({
      name = f"status_bar.{tab}",
      x = "0%", y = "0%",
      width = "100%", height = "100%",
      hidden = true
    }, self.container)
    self[tab]:echo(self.tab_settings[tab].default_text)
    self[tab]:setStyleSheet([[
      background-color: black;
      border: 1px solid gray;
      qproperty-alignment: 'AlignVCenter | AlignHCenter';
    ]])
  end
end

function status_bar:update_health_on_tic(event, exact, is_early, is_late) if is_early then self.char.con = self.char.con or 1 local hp_regen = {0, 0, 0, 0, 0, 0, 0, 0, 18, 21, 22, 25, 26, 29, 30, 33, 35, 37, 39}
local msg = self:update_table_on_tic(self.char.hps, 0, hp_regen[self.char.con], "Hit Points", "HP") self.hps:echo(msg, "white", "c") end end
registerAnonymousEventHandler("tic", "status_bar:update_health_on_tic")

function status_bar:is_weaving(event, com) com = com:lower()
if table.contains({"chann", "channe", "channel"}, com:split()[1]) then local weave = com:match("'(.+)'")
if weave then self:update_sps_with_weave(weave) end end end
registerAnonymousEventHandler("sysDataSendRequest", "status_bar:is_weaving")
